def binary_file_io(filepath, mode, data=None):
    if mode == 'read':
        with open(filepath, 'rb') as f:
            return f.read()
    elif mode == 'write':
        if data is None:
            raise ValueError("Data must be provided for write mode.")
        with open(filepath, 'wb') as f:
            f.write(data)
    else:
        raise ValueError("Mode must be 'read' or 'write'.")
